python3 -c "
import xml.etree.ElementTree as ET
tree = ET.parse('/work/output/artifacts/skill-bpmn-transform-filter/TransformFilterDemo.bpmn')
root = tree.getroot()

ns = {
    'bpmn': 'http://www.omg.org/spec/BPMN/20100524/MODEL',
    'bpmndi': 'http://www.omg.org/spec/BPMN/20100524/DI',
    'uipath': 'http://uipath.org/schema/bpmn',
}

errors = []

# 1. Root is definitions with BPMN namespace
assert 'http://www.omg.org/spec/BPMN/20100524/MODEL' in root.tag or 'definitions' in root.tag.lower(), 'Bad root'

# 2. Collect all flow node ids and sequence flow ids
process = root.find('bpmn:process', ns)
all_ids = set()
for el in process.iter():
    eid = el.get('id')
    if eid:
        all_ids.add(eid)

seq_flows = process.findall('bpmn:sequenceFlow', ns)
flow_ids = {f.get('id') for f in seq_flows}

# 3. All sourceRef/targetRef resolve
for sf in seq_flows:
    src = sf.get('sourceRef')
    tgt = sf.get('targetRef')
    if src not in all_ids:
        errors.append(f'sourceRef {src} not found')
    if tgt not in all_ids:
        errors.append(f'targetRef {tgt} not found')

# 4. Diagram: collect shapes and edges
diagram = root.find('bpmndi:BPMNDiagram', ns)
plane = diagram.find('bpmndi:BPMNPlane', ns)
shape_refs = {s.get('bpmnElement') for s in plane.findall('bpmndi:BPMNShape', ns)}
edge_refs  = {e.get('bpmnElement') for e in plane.findall('bpmndi:BPMNEdge', ns)}

# Every flow node has a shape
node_tags = {'startEvent','endEvent','scriptTask','task','serviceTask','userTask','exclusiveGateway','parallelGateway'}
for el in process:
    tag = el.tag.split('}')[-1] if '}' in el.tag else el.tag
    if tag in node_tags:
        eid = el.get('id')
        if eid not in shape_refs:
            errors.append(f'Node {eid} has no BPMNShape')

# Every flow has an edge
for fid in flow_ids:
    if fid not in edge_refs:
        errors.append(f'Flow {fid} has no BPMNEdge')

# 5. scriptTask checks
for st in process.findall('bpmn:scriptTask', ns):
    fmt = st.get('scriptFormat')
    if fmt != 'JavaScript':
        errors.append(f'scriptTask {st.get(\"id\")} missing scriptFormat=JavaScript')
    ext = st.find('bpmn:extensionElements', ns)
    sv = ext.find('uipath:scriptVersion', ns) if ext is not None else None
    if sv is None or sv.get('value') != 'v3':
        errors.append(f'scriptTask {st.get(\"id\")} missing scriptVersion v3')
    script = st.find('bpmn:script', ns)
    if script is None or not script.text:
        errors.append(f'scriptTask {st.get(\"id\")} has no script body')
    else:
        body = script.text
        if 'filter' not in body:
            errors.append('script body missing filter')
        if 'amount' not in body or '100' not in body:
            errors.append('script body missing amount >= 100 logic')

if errors:
    print('ERRORS:', errors)
else:
    print('VALID - all structural checks passed')
